16	const PROCESSING_FEE = 5;
17	const BASE_PREMIUMS: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	const FIRST_INSURANCE_SURCHARGE = 0.1;
24	
25	// Rounds up in MHPCO's favor, guarding against floating-point drift
26	// (e.g. 197.50000000001 should round to 198, not be inflated by noise).
27	const roundUpInFavor = (amount: number): number =>
28	  Math.ceil(Number(amount.toFixed(6)));
29	
30	const COMPONENT_TYPES = new Set(["rune"]);
31	const COMPONENT_BASE_PREMIUM = 25;
32	const BLOCK_SIZE = 3;
33	const BLOCK_BASE_PREMIUM = 60;
34	
35	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
36	
37	// Components of the same type form blocks of BLOCK_SIZE priced at BLOCK_BASE_PREMIUM;
38	// leftover loose components are priced individually.
39	const componentGroupBasePremium = (count: number): number =>
40	  count === BLOCK_SIZE
41	    ? BLOCK_BASE_PREMIUM
42	    : count * COMPONENT_BASE_PREMIUM;
43	
44	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
45	
46	const countByType = (items: Item[]): Record<string, number> =>
47	  items.reduce<Record<string, number>>((counts, item) => {
48	    counts[item.type] = (counts[item.type] ?? 0) + 1;
49	    return counts;
50	  }, {});
51	
52	const sum = (values: number[]): number =>
53	  values.reduce((running, value) => running + value, 0);
54	
55	const basePremiumTotal = (items: Item[]): number => {
56	  const mainItems = items.filter((item) => !isComponent(item));
57	  const components = items.filter(isComponent);
58	
59	  const mainItemsTotal = sum(mainItems.map(itemBasePremium));
60	  const componentsTotal = sum(
61	    Object.values(countByType(components)).map(componentGroupBasePremium),
62	  );
63	
64	  return mainItemsTotal + componentsTotal;
65	};
66	
67	export const quote = (customer: Customer, items: Item[]): QuoteResult => {
68	  const itemsPremiumTotal =
69	    basePremiumTotal(items) * (1 + FIRST_INSURANCE_SURCHARGE);
70	  const exactPremium = itemsPremiumTotal + PROCESSING_FEE;
71	  return { premium: roundUpInFavor(exactPremium) };
72	};
73	
74	export const claim = (...args: unknown[]): unknown => {
75	  return undefined;
76	};
